#include <bits/stdc++.h>
#define int long long
using namespace std;
int l, r, dp[20][200][200];
int len, a[20], mod;
int dfs (int pos, int sum, int st, int limit) {
	if (pos > len && sum == 0) {
		return 0;
	}
	if (pos > len) {
		return st == 0 && sum == mod ? 1 : 0;
	}
	if (!limit && dp[pos][sum][st] != -1) {
		return dp[pos][sum][st];
	}
	int ret = 0;
	int res = limit ? a[len - pos + 1] : 9;
	for (int i = 0; i <= res; i++) {
		ret += dfs (pos + 1, sum + i, (10ll * st + i) % mod, i == res && limit);
	}
	return limit ? ret : dp[pos][sum][st] = ret;
}
int solve (int x) {
	len = 0;
	while (x) {
		a[++len] = x % 10;
		x /= 10;
	}
	int ret = 0;
	for (mod = 1; mod <= 9 * len; mod++) {
		memset (dp, -1, sizeof (dp));
		ret += dfs (1, 0, 0, 1);
	}
	return ret;
}
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	int l, r;
	cin >> l >> r;
	cout << solve (r) - solve (l - 1);
	return 0;
}
